+/// Yields sample indices sequentially: 0, 1, 2, ..., n-1.
+pub struct SequentialSampler {
+    size: usize,
+}
+
+impl SequentialSampler {
+    pub fn new(size: usize) -> Self {
+        Self { size }
+    }
+
+    pub fn len(&self) -> usize {
+        self.size
+    }
+
+    pub fn is_empty(&self) -> bool {
+        self.size == 0
+    }
+
+    pub fn indices(&self) -> Vec<usize> {
+        (0..self.size).collect()
+    }
+}
+
+/// Yields a random permutation of 0..n, or samples with replacement.
+pub struct RandomSampler {
+    size: usize,
+    replacement: bool,
+    num_samples: usize,
+    seed: u64,
+}
+
+impl RandomSampler {
+    pub fn new(size: usize) -> Self {
+        Self {
+            size,
+            replacement: false,
+            num_samples: size,
+            seed: 0xCAFE_BABE_1234_5678,
+        }
+    }
+
+    pub fn with_replacement(mut self, replacement: bool) -> Self {
+        self.replacement = replacement;
+        self
+    }
+
+    pub fn with_num_samples(mut self, num_samples: usize) -> Self {
+        self.num_samples = num_samples;
+        self
+    }
+
+    pub fn with_seed(mut self, seed: u64) -> Self {
+        self.seed = seed;
+        self
+    }
+
+    pub fn len(&self) -> usize {
+        self.num_samples
+    }
+
+    pub fn is_empty(&self) -> bool {
+        self.num_samples == 0
+    }
+
+    pub fn indices(&self) -> Vec<usize> {
+        let mut rng = SimpleRng::new(self.seed);
+        if self.replacement {
+            (0..self.num_samples)
+                .map(|_| rng.next_below(self.size))
+                .collect()
+        } else {
+            let mut idx: Vec<usize> = (0..self.size).collect();
+            rng.shuffle(&mut idx);
+            idx.truncate(self.num_samples);
+            idx
+        }
+    }
+}
