+/// Configuration for a `DataLoader`.
+pub struct DataLoaderConfig {
+    /// Number of samples per batch.
+    pub batch_size: usize,
+    /// Whether to shuffle data each epoch.
+    pub shuffle: bool,
+    /// Whether to drop the last incomplete batch.
+    pub drop_last: bool,
