+        let log_probs = make_log_probs(&mut session, lp_data, 3, 1, 2);
+        let targets = session.tensor_variable(vec![1.0, 1.0], vec![1, 2], false).unwrap();
+        let input_lengths = session.tensor_variable(vec![3.0], vec![1], false).unwrap();
